// pages/CollectionPage.js
import { useState } from 'react';
import Header from '../components/Header';
import styles from './CollectionPage.module.css';

const womenSS26Collection = Array.from({ length: 100 }, (_, i) => ({
  id: i + 1,
  src: `https://recto.co/img/ss26/collection/women/${i + 1}.jpg`,
  label: 'Women SS26',
}));

export default function CollectionPage() {
  const [activeIndex, setActiveIndex] = useState(0);
  const activeItem = womenSS26Collection[activeIndex];

  return (
    <>
      <Header />
      <div className={styles.page}>
      {/* 왼쪽 히어로 */}
      <div className={styles.heroPanel}>
        <div className={styles.heroImageWrap}>
          <img
            key={activeItem.id}
            src={activeItem.src}
            alt={activeItem.label}
            className={styles.heroImage}
          />
        </div>
        <div className={styles.heroMeta}>
          <span className={styles.heroLabel}>{activeItem.label}</span>
          <span className={styles.heroIndex}>
            {String(activeIndex + 1).padStart(2, '0')} /{' '}
            {String(womenSS26Collection.length).padStart(2, '0')}
          </span>
        </div>
      </div>

      {/* 오른쪽 썸네일 그리드 */}
      <div className={styles.gridPanel}>
        <p className={styles.gridTitle}>Women SS26</p>
        <div className={styles.grid}>
          {womenSS26Collection.map((item, index) => (
            <button
              key={item.id}
              className={`${styles.thumb} ${index === activeIndex ? styles.thumbActive : ''}`}
              onClick={() => setActiveIndex(index)}
            >
              <img
                src={item.src}
                alt={`look ${item.id}`}
                className={styles.thumbImage}
              />
            </button>
          ))}
        </div>
      </div>
    </div>
    </>
  );
}
